const exactMoveMediaNames=new Set(["Ankle rockers","Balance reset","Bear crawl hold","Bent-knee brace","Bird dog crunch","Bird dog hover","Bird dog","Bodyweight squat","Bridge breathing","Calisthenics skill flow","Chair tap squat","Counter push-up","Crow-prep balance","Dead bug pause","Dead bug","Forearm plank","Glute bridge hold","Glute bridge","Heel taps","High plank hold","Incline push-up","Kickstand bridge","Knee plank","L-sit tuck prep","Long-lever dead bug","Long-lever plank","Marching bridge","Mobility squat flow","Pause push-up","Plank shoulder tap prep","Posture builder","Quadruped brace","Quiet conditioning circuit","Quiet high-knee march","Recovery reset flow","Short side plank","Side plank hold","Side plank reach","Side plank rotation prep","Side plank","Single-leg bridge prep","Single-leg calf prep","Sit-to-stand","Skill prep flow","Slow eccentric calf raise","Slow negative push-up","Squat pulse","Squat-to-reach","Standing calf raise","Supported calf raise","Tempo squat","Three-point hold","Tucked hollow hold","Wall push-up"]);
function sourcingPlan(name:string){const n=name.toLowerCase();
 if(n.includes("push"))return{lead:"Push variation lead",query:`exact real human ${name} exercise demo commercial license mp4 no animation no YouTube`,provider:"YMove API, Pexels licensed stock, IFPE/FAME only after written rights confirmation",url:"https://ymove.app/exercise-api",route:"License a matching clip, then trim to the first clean rep and save as a Bodywise loop."};
 if(n.includes("squat")||n.includes("stand")||n.includes("knee"))return{lead:"Knee + squat lead",query:`exact real human ${name} exercise demo sit stand squat commercial license mp4`,provider:"YMove, Central Athlete EVL, FAME/clinic clips after written app-use permission",url:"https://www.centralathlete.com/exercise-video-library",route:"Prioritize frontal/side view, knee tracking visible, no chair reuse unless the move is actually chair-based."};
 if(n.includes("plank")||n.includes("dead bug")||n.includes("bird")||n.includes("heel")||n.includes("bear"))return{lead:"Core control lead",query:`exact real human ${name} rehab core exercise demo licensed mp4 no animation`,provider:"MuscleWiki API, YMove, physio libraries only with confirmed redistribution rights",url:"https://api.musclewiki.com/",route:"Verify the named position, crop away introductions, and loop 2-3 clean reps or one stable hold."};
 if(n.includes("bridge")||n.includes("calf")||n.includes("ankle")||n.includes("march"))return{lead:"Lower-body support lead",query:`exact real human ${name} exercise demo licensed mp4 real person`,provider:"YMove, Central Athlete EVL, wger when exact, or Bodywise studio capture",url:"https://ymove.app/exercise-video-library",route:"Use only clips where the lower-body action is unmistakable and starts directly at movement."};
 return{lead:"Exact movement lead",query:`exact real human ${name} calisthenics exercise demo commercial license mp4`,provider:"YMove / MuscleWiki / Kinetic.place / Bodywise studio capture",url:"https://kinetic.place/",route:"If no source passes, shoot a 15-25 second Bodywise clip instead of substituting a lookalike."}}
function ExactClipNeeded({name,large=false}:{name:string;large?:boolean}){const s=sourcingPlan(name);return <div className={"movement-media media-needed "+(large?"large":"")}><div><b>Secure exact clip</b><p>No lookalike video is shown for {name}. Next action: identify, verify, license or shoot the exact real-person movement.</p><ul className="media-actions"><li><span>Search phrase</span><em>{s.query}</em></li><li><span>Best source route</span><em>{s.provider}</em></li><li><span>Approval rule</span><em>Named move must match, real human only, two arms/two legs visible when relevant, no extra or warped limbs, no intro/title card, rights cleared for app use.</em></li><li><span>Production fallback</span><em>{s.route}</em></li></ul><a className="source-link" href={s.url} target="_blank" rel="noreferrer">Open {s.lead}</a></div></div>}
function hasVaultDemo(item:(typeof vault)[number],move:Move){return Boolean(vaultExactVideos[item.name])}
function VaultMedia({item,move}:{item:(typeof vault)[number];move:Move}){const v=vaultExactVideos[item.name];if(v)return <div className="movement-media large vault-direct" data-source="bodywise-demo"><video src={v.src} poster={v.poster||move.image} autoPlay loop muted playsInline preload="auto" aria-label={item.name+" exact Bodywise movement demo"}/><div className="media-shade"/><span className="media-credit">{v.credit}</span><span className="loop-badge">↻ EXACT DEMO</span></div>;return <ExactClipNeeded name={item.name} large/>}
function ClipCard({x}:{x:ShortLoopClip}){return <article className={x.ready?"ready":"candidate"} key={x.move+x.source}>{x.preview?<div className="clip-preview">{x.media==="image"?<img src={x.preview} alt={x.move+" short Bodywise movement demo"}/>:<video src={x.preview} poster={x.poster} muted loop autoPlay playsInline preload="metadata" aria-label={x.move+" short Bodywise loop demo"}/>}<b>{x.ready?"APPROVED":"VIEWABLE"}</b></div>:<a className="clip-link-preview" href={x.url} target="_blank" rel="noreferrer"><span>OPEN SOURCE</span><b>{x.move}</b></a>}<div className="clip-copy"><small>{x.ready?"APPROVED LOOP":"VIEWABLE EXACT PREVIEW"}</small><h3>{x.move}</h3><p>{x.loop}</p><em>{x.status}</em><a href={x.url} target="_blank" rel="noreferrer">Review source →</a></div></article>}function ClipCollectionBoard(){const ready=shortLoopCollection.filter(x=>x.ready),queued=shortLoopCollection.filter(x=>!x.ready);return <section className="clip-collection-board"><div className="clip-collection-head"><div><p className="eyebrow">CLIP COLLECTION</p><h2>Bodywise-owned movement demos</h2><p>Every card below shows the named movement from a local Bodywise asset, so the app no longer depends on borrowed third-party preview clips.</p></div><span>{ready.length} APPROVED · {queued.length} PREVIEWS</span></div><div className="clip-subhead"><b>Owned loops</b><small>Playable local Bodywise assets</small></div><div className="clip-grid ready-grid">{ready.map(x=><ClipCard x={x} key={x.move+x.source}/>)}</div><div className="clip-subhead queued"><b>Ready in app</b><small>No external clip dependency</small></div><div className="clip-grid queued-grid">{queued.map(x=><ClipCard x={x} key={x.move+x.source}/>)}</div></section>}function MuscleWikiMappingBoard(){
 const[selected,setSelected]=useState(muscleWikiReviewQueue[0]),[results,setResults]=useState<MuscleWikiCandidate[]>([]),[loading,setLoading]=useState(false),[error,setError]=useState("");
 async function search(item=selected){setSelected(item);setLoading(true);setError("");setResults([]);try{const res=await fetch("/api/musclewiki/search?q="+encodeURIComponent(item.query));const data=await res.json();if(!res.ok){setError(data.upgradeUrl?data.error+" Upgrade direct API access to activate live search.":data.error||"MuscleWiki search failed.");return}setResults(data.results||[])}catch{setError("Could not reach the Bodywise MuscleWiki connector.")}finally{setLoading(false)}}
 return <section className="musclewiki-board"><div className="mw-head"><div><p className="eyebrow">MUSCLEWIKI CONNECTOR</p><h2>Search, approve, then stream</h2><p>Bodywise now routes MuscleWiki through a private backend. A clip is mapped only after the movement name, real-human footage and starting frame pass review.</p></div><button onClick={()=>search()}>{loading?"Searching…":"Search selected"}</button></div><div className="mw-approved">{approvedMuscleWikiMappings.map(x=><article key={x.move}><b>{x.move}</b><span>{x.source}</span><p>{x.status}</p></article>)}</div><div className="mw-workbench"><div className="mw-queue">{muscleWikiReviewQueue.map(item=><button key={item.bodywise} className={selected.bodywise===item.bodywise?"selected":""} onClick={()=>search(item)}><b>{item.bodywise}</b><span>{item.query}</span><small>{item.status}</small></button>)}</div><div className="mw-results"><h3>{selected.bodywise}</h3><p><b>Approval rule:</b> {selected.rule}</p>{error&&<div className="mw-error">{error}</div>}{!error&&!loading&&results.length===0&&<div className="mw-empty">Tap Search selected to pull candidates. Basic MuscleWiki keys may show an upgrade notice here.</div>}{loading&&<div className="mw-empty">Searching MuscleWiki through the Bodywise connector…</div>}{results.map(r=><article key={r.id}><div><b>{r.name}</b><span>{r.category||"Bodyweight"} · {r.difficulty||"difficulty unknown"}</span><small>{r.muscles.join(" · ")||"Muscles not listed"}</small></div><em>{r.videoCount} video option{r.videoCount===1?"":"s"}</em><p>{r.name.toLowerCase()===selected.bodywise.toLowerCase()?"Name match — still verify the actual movement before approval.":"Review required — do not auto-map unless the clip exactly matches Bodywise’s named move."}</p></article>)}</div></div></section>
}
function workTime(base:number,age:string,level:Level,readiness:Readiness){const a:Record<string,number>={"13–17":.9,"18–29":1,"30–44":1,"45–59":.9,"60+":.78},l:Record<Level,number>={Beginner:.82,Intermediate:1,Advanced:1.18},r:Record<Readiness,number>={Recover:.72,Ready:1,Push:1.12};return Math.max(20,Math.round(base*a[age]*l[level]*r[readiness]/5)*5)}
function MovementMedia({move,large=false}:{move:Move;large?:boolean}){const preview=exactPreviewByMoveName.get(movePreviewAliases[move.name]||move.name);if(preview)return <div className={"movement-media "+(large?"large":"")} data-source="bodywise-demo">{preview.media==="image"?<img src={preview.preview} alt={move.name+" exact Bodywise movement demo"}/>:<video src={preview.preview} poster={preview.poster||move.image} autoPlay loop muted playsInline preload={large?"auto":"metadata"} aria-label={move.name+" exact Bodywise movement demo"}/>}<div className="media-shade"/><span className="media-credit">{preview.source}</span><span className="loop-badge">↻ BODYWISE DEMO</span></div>;if(!exactMoveMediaNames.has(move.name))return <ExactClipNeeded name={move.name} large={large}/>;return <div className={"movement-media "+(large?"large":"")}><video src={move.video} poster={move.image} autoPlay loop muted playsInline preload={large?"auto":"metadata"} aria-label={move.name+" exact real-person movement demonstration"}/><div className="media-shade"/>{move.credit&&<span className="media-credit">{move.credit}</span>}<span className="loop-badge">↻ EXACT VIDEO</span></div>}
export default function Home(){
 const[goal,setGoal]=useState<Goal>("Full body"),[age,setAge]=useState("30–44"),[sex,setSex]=useState<Sex>("Prefer not to say"),[level,setLevel]=useState<Level>("Beginner"),[limitation,setLimitation]=useState<Limitation>("None"),[readiness,setReadiness]=useState<Readiness>("Ready");
 const[profile,setProfile]=useState(false),[adapt,setAdapt]=useState(false),[session,setSession]=useState(false),[finish,setFinish]=useState(false),[showWhy,setShowWhy]=useState(false),[showLibrary,setShowLibrary]=useState(false),[showProof,setShowProof]=useState(false),[showUpgrade,setShowUpgrade]=useState(false),[vaultMove,setVaultMove]=useState<(typeof vault)[number]|null>(null),[running,setRunning]=useState(false),[active,setActive]=useState(0),[left,setLeft]=useState(0),[tab,setTab]=useState<Tab>("Today"),[targetMinutes,setTargetMinutes]=useState(20),[quiet,setQuiet]=useState(false),[caption,setCaption]=useState(true),[audioHints,setAudioHints]=useState(true),[kudos,setKudos]=useState(18),[rotation,setRotation]=useState(0),[previewIndex,setPreviewIndex]=useState(0),[convexReady,setConvexReady]=useState(false);
 const goalData=goals[goal],keys=goalData.rotations[rotation%goalData.rotations.length],plan=useMemo(()=>keys.map((k,i)=>({...M[k],seconds:workTime(M[k].base+(i%2?5:0),age,level,readiness)})),[keys,age,level,readiness]),minutes=targetMinutes,current=plan[active]||plan[0],freshness=Math.min(96,62+rotation*7+Object.keys(goals).indexOf(goal)*2),identity=goal==="Knee strength"?"Knee Confidence":goal==="Enhanced core"?"Core Control":goal==="Arm strength"?"Push Strength":goal==="Lower body"?"Lower-Body Power":goal==="Mobility & Recovery"?"Mobility Ease":goal==="No-jump Conditioning"?"Quiet Engine":goal==="Skill Prep"?"Skill Builder":goal==="Balance & Posture"?"Posture Balance":"Bodywise Foundation",confidenceScore=Math.min(94,68+rotation*4+(level==="Advanced"?8:level==="Intermediate"?5:2)+(readiness==="Push"?4:readiness==="Recover"?-2:1)); const preview=plan[previewIndex]||plan[0];
 useEffect(()=>{const raw=localStorage.getItem("bodywise-profile");if(raw){try{const p=JSON.parse(raw);if(p.goal&&goals[p.goal as Goal])setGoal(p.goal);if(p.age)setAge(p.age);if(p.sex)setSex(p.sex);if(p.level)setLevel(p.level);if(p.limitation)setLimitation(p.limitation)}catch{}}},[]);
 useEffect(()=>{fetch("/api/convex/status").then(r=>r.ok?r.json():null).then(d=>setConvexReady(Boolean(d?.connected))).catch(()=>setConvexReady(false))},[]);
 useEffect(()=>{if(!running||left<=0)return;const t=window.setInterval(()=>setLeft(v=>v-1),1000);return()=>clearInterval(t)},[running,left]); useEffect(()=>{if(session)setLeft(current.seconds)},[active,current.seconds,session]);
 function chooseGoal(next:Goal){setGoal(next);setActive(0);setPreviewIndex(0);setSession(false);setRunning(false);setRotation(0)} function saveProfile(){localStorage.setItem("bodywise-profile",JSON.stringify({goal,age,sex,level,limitation}));setProfile(false)} function start(){setActive(0);setLeft(plan[0].seconds);setRunning(true);setFinish(false);setSession(true)} function next(){if(active===plan.length-1){setSession(false);setRunning(false);setFinish(true)}else{setActive(v=>v+1);setRunning(true)}} function scrollPreviewGallery(dir:1|-1){const rail=document.getElementById("clear-preview-gallery");if(rail)rail.scrollBy({left:dir*Math.max(260,rail.clientWidth*.82),behavior:"smooth"})}
 return <main className="app-shell">
  <header className="topbar premium-topbar"><button className="brand" onClick={()=>setTab("Today")} aria-label="Bodywise home"><b>B</b>BODYWISE</button><div className="top-actions"><span className="streak-pill">⚡ {freshness}% FRESH</span><button className="profile-pill" onClick={()=>setProfile(true)} aria-label="Open training profile"><span>{age}</span><b>{sex==="Female"?"F":sex==="Male"?"M":"·"}</b></button></div></header>
  {tab==="Today"&&<><section className="intro home-hero"><div className="hero-date"><p className="eyebrow">ROTATION {rotation+1} · WEEK 2</p><span>{goal.toUpperCase()}</span></div><h1>Never the<br/><em>same.</em></h1><p>Choose a target, spin a fresh bodyweight session, and follow exact matching movement clips only — no borrowed or lookalike videos.</p><div className="hero-proof"><span><b>{vault.length}</b> variations mapped</span><span><b>{plan.length}</b> moves today</span></div></section>
  <section className="premium-entry">
   <div className="entry-copy"><p className="eyebrow">TRY BODYWISE FREE</p><h2>Your safest next move, today.</h2><p>Start instantly. Bodywise uses your goal, age range, experience, readiness and limitations to build guidance that adapts to your body — not just your motivation.</p><div className="entry-actions"><button onClick={start}>Start free session <b>→</b></button><button onClick={()=>setProfile(true)}>Personalise</button></div></div>
   <div className="entry-video"><MovementMedia move={current} large/><span>{current.name}</span></div>
  </section>
  <section className="trust-ribbon"><span><b>{convexReady?"Cloud":"Free"}</b> {convexReady?"save ready":"instant start"}</span><span><b>{Object.keys(goals).length}</b> goal paths</span><span><b>{freshness}%</b> fresh today</span></section><section className="confidence-card"><div><p className="eyebrow">BODY CONFIDENCE PATH</p><h2>{identity}</h2><p>Not a medical score — a friendly progress identity based on your goal, level, readiness and movement variety.</p></div><b>{confidenceScore}<small>/100</small></b><span>{limitation==="None"?"No limitation flagged":"Adapting for "+limitation.toLowerCase()}</span></section>
  <section className="readiness-row premium-pace"><div><p className="eyebrow">TODAY'S FEEL</p><h2>{readiness} pace</h2></div><div>{(["Recover","Ready","Push"] as Readiness[]).map(x=><button key={x} className={readiness===x?"selected":""} onClick={()=>setReadiness(x)}>{x}</button>)}</div></section>
  <section className="target-section premium-targets"><div className="target-heading"><div><p className="eyebrow">CHOOSE YOUR RESULT</p><h2>{goal}</h2></div><b>{Object.keys(goals).length} PATHS</b></div><div className="target-grid">{(Object.keys(goals) as Goal[]).map(name=><button className={goal===name?"selected":""} onClick={()=>chooseGoal(name)} key={name}><i>{goals[name].icon}</i><span>{name}</span><small>{goals[name].desc}</small>{goal===name&&<b>✓</b>}</button>)}</div>{goal==="Knee strength"&&<p className="knee-note">Knee work should feel controlled, not painful. If pain persists, ask a qualified clinician.</p>}</section>
  <section className="workout featured-workout premium-workout"><div className="workout-media"><MovementMedia move={current} large/></div><div className="shade"/><div className="workout-copy"><span className="tag">TODAY'S COACHED SESSION</span><div className="coach-byline"><i>K</i><span>Coach Kai · {readiness} pace · Rotation {rotation+1}</span></div><h2>{goalData.title}</h2><p>{quiet?"Quiet mode is on: no jumping and apartment-friendly movement.":goalData.promise}</p><div className="stats"><span><b>{minutes}</b> min</span><span><b>{plan.length}</b> moves</span><span><b>3</b> rounds</span></div></div><button className="start" onClick={start}>Begin workout <b>→</b></button></section>
  <section className="premium-control-grid"><button onClick={()=>{setRotation(v=>(v+1)%3);setActive(0)}}><span>↻</span><b>Shuffle fresh session</b><small>Same goal, new rotation</small></button><button onClick={()=>setAdapt(true)}><span>⚙</span><b>Adapt today</b><small>Time, intensity, quiet mode</small></button><button onClick={()=>setShowLibrary(v=>!v)}><span>▦</span><b>{showLibrary?"Hide":"Explore"} movement library</b><small>{vault.length} exact-guided moves</small></button><button onClick={()=>setShowProof(v=>!v)}><span>✓</span><b>{showProof?"Hide":"Show"} quality proof</b><small>No convenience reuse</small></button></section>
  <section className="today-preview preview-gallery-section"><div className="preview-top"><div><p className="eyebrow">NEXT MOVES · SCROLL ALL PREVIEWS</p><h2>Clear movement previews</h2></div><div className="gallery-controls"><button type="button" onClick={()=>scrollPreviewGallery(-1)} aria-label="Scroll previews left">‹</button><button type="button" onClick={()=>scrollPreviewGallery(1)} aria-label="Scroll previews right">›</button></div></div><div id="clear-preview-gallery" className="clear-preview-gallery">{plan.map((x,i)=><article className="clear-preview-card" key={x.name}><button type="button" className="clear-preview-media" onClick={()=>{setActive(i);setSession(true);setLeft(x.seconds);setRunning(false)}} aria-label={"Open "+x.name+" movement preview"}><MovementMedia move={x}/></button><div className="clear-preview-copy"><span>{String(i+1).padStart(2,"0")} / {plan.length}</span><h3>{x.name}</h3><p>{x.seconds}s · {x.focus}</p><small>{x.cue}</small></div></article>)}</div><p className="gallery-hint">Swipe the cards left/right, or tap the arrows. Every move in today&apos;s workout has its own visual preview.</p></section>
  <section className="conversion-card"><div><p className="eyebrow">UNLOCK AFTER YOUR FIRST SESSION</p><h2>Your 4-week {identity} path.</h2><p>Keep the free starter workout. Upgrade only when you want a saved plan that adjusts weekly, avoids repetition, and gives safer alternatives for your body.</p><div className="value-grid"><span><b>7 days</b> trial</span><span><b>$59</b> yearly best value</span><span><b>{vault.length}</b> move vault</span></div></div><button onClick={()=>setShowUpgrade(true)}>Preview premium →</button></section><section className="free-premium-split"><article><span>FREE START</span><h3>Useful before signup</h3><p>Daily starter workout, basic timer, selected goal paths, and a limited movement vault.</p></article><article><span>PREMIUM PATH</span><h3>Built to retain users</h3><p>4-week progression, saved progress, weekly adjustments, full video library, recovery routines, and replace-this-move alternatives.</p></article></section>
  {showLibrary&&<><section className="packs compact-section"><p className="eyebrow">MOVEMENT FAMILIES</p><h2>More variety, less randomness</h2><div>{plan.map(x=><article key={x.name}><MovementMedia move={x}/><div><small>{x.family} · {x.intensity}</small><h3>{x.name}</h3><p>{x.detail}</p><em className="move-why">{x.why}</em><div>{x.variants.map(v=><span key={v}>{v}</span>)}</div></div></article>)}</div></section><section className="vault-card compact-section"><div><p className="eyebrow">MOVE VAULT</p><h2>{vault.length} ways to keep growing</h2><p>Tap any move for exact media, cues and progression context.</p></div><div>{vault.map(v=><button key={v.name} onClick={()=>setVaultMove(v)}><span>{v.name}</span><small>{M[v.move].family}</small><em>{vaultDescription(v,M[v.move])}</em></button>)}</div></section><section className="section-head compact-head"><div><p className="eyebrow">YOUR TARGETED PLAN</p><h2>{goal} movements</h2></div><span>{plan.length} selected</span></section><section className="exercise-list compact-section">{plan.map((x,i)=><article className="exercise" key={x.name}><div className="exercise-image"><MovementMedia move={x}/></div><div className="exercise-copy"><small>0{i+1} · {x.focus}</small><h3>{x.name}</h3><p>{x.cue}</p><span>{x.detail}</span></div><aside><b>{x.seconds}</b><small>SEC</small></aside></article>)}</section></>}
  {showProof&&<><section className="recovery-card compact-section"><div><p className="eyebrow">ESTIMATED RECOVERY</p><h2>Your body map</h2><small>Based on recent sessions—not a medical measurement.</small></div><div className="recovery-bars"><span><i style={{width:"82%"}}/>Core <b>82%</b></span><span><i style={{width:"64%"}}/>Upper <b>64%</b></span><span><i style={{width:"91%"}}/>Lower <b>91%</b></span></div><button className="why-button" onClick={()=>setShowWhy(v=>!v)} aria-expanded={showWhy}>{showWhy?"Hide":"Why this workout?"}<b>{showWhy?"−":"+"}</b></button>{showWhy&&<div className="why-copy"><b>Why Bodywise chose this</b><p>This rotation matches your {goal} target, {readiness} pace, age range and current time window. No convenience reuse is allowed: exact matching clips display everywhere.</p></div>}</section><ClipCollectionBoard/><section className="source-pass-card compact-section"><div><p className="eyebrow">VIDEO SOURCE PASS</p><h2>Synced media pass</h2><p>Bodywise keeps Today, Move Vault, clip collection and review status in sync: exact demos appear everywhere instead of borrowing related videos.</p></div><div>{premiumSourcePlan.map(x=><article key={x.name}><b>{x.name}</b><span>{x.fit}</span><p>{x.note}</p></article>)}</div><div className="candidate-source-list"><h3>Resolved clips and active review queue</h3>{candidateSourcePass.map(x=><article key={x.move}><b>{x.move}</b><span>{x.source}</span><p>{x.status}</p></article>)}</div></section><MuscleWikiMappingBoard/></>}
</>}
  {tab==="Plan"&&<PlanPage goal={goal} minutes={minutes}/>} {tab==="Community"&&<CommunityPage kudos={kudos} onKudos={()=>setKudos(v=>v+1)}/>} {tab==="Progress"&&<ProgressPage goal={goal}/>} 
  <nav className="bottom-nav provider-nav">{nav.map((x,i)=><button className={tab===x?"selected":""} onClick={()=>setTab(x)} key={x}><span>{["●","▤","◎","◔"][i]}</span>{x}</button>)}</nav>
  {adapt&&<div className="overlay" role="dialog" aria-modal="true"><button className="backdrop" onClick={()=>setAdapt(false)} aria-label="Close"/><section className="sheet adapt-sheet"><i/><button className="close" onClick={()=>setAdapt(false)}>×</button><p className="eyebrow">FREE UP THE PLAN</p><h2>Adapt today.</h2><fieldset><legend>Time available</legend><div className="choices">{[10,15,20].map(x=><button className={targetMinutes===x?"chosen":""} onClick={()=>setTargetMinutes(x)} key={x}>{x} min</button>)}</div></fieldset><fieldset><legend>Energy</legend><div className="choices">{(["Recover","Ready","Push"] as Readiness[]).map(x=><button className={readiness===x?"chosen":""} onClick={()=>setReadiness(x)} key={x}>{x}</button>)}</div></fieldset><label className="quiet-toggle"><span><b>Quiet mode</b><small>No jumping · small-space friendly</small></span><input type="checkbox" checked={quiet} onChange={e=>setQuiet(e.target.checked)}/></label><button className="save" onClick={()=>setAdapt(false)}>Update today’s workout</button></section></div>}
  {vaultMove&&<div className="overlay" role="dialog" aria-modal="true"><button className="backdrop" onClick={()=>setVaultMove(null)} aria-label="Close"/><section className="sheet vault-sheet"><i/><button className="close" onClick={()=>setVaultMove(null)}>×</button><p className="eyebrow">MOVE VAULT GUIDE</p><h2>{vaultMove.name}</h2><div className="vault-visual"><VaultMedia item={vaultMove} move={M[vaultMove.move]}/></div><div className="vault-guide-copy"><small>{M[vaultMove.move].family} · {M[vaultMove.move].intensity}</small><h3>{M[vaultMove.move].cue}</h3><b>How to do it</b><p>{vaultDescription(vaultMove,M[vaultMove.move])}</p><b>Coach notes</b><p>{M[vaultMove.move].detail}</p><b>Why it matters</b><p>{M[vaultMove.move].why}</p><b>Progressions</b><div>{M[vaultMove.move].variants.map(x=><span key={x}>{x}</span>)}</div><em>{hasVaultDemo(vaultMove,M[vaultMove.move])?"Bodywise demo: local clip shown inside the Move Vault.":"No Bodywise demo is shown yet; add an owned or approved clip before marking this move complete."}</em></div><button className="save" onClick={()=>{setVaultMove(null);setGoal("Skill Prep");setTab("Today")}}>Train related moves</button></section></div>}
  {profile&&<div className="overlay" role="dialog" aria-modal="true"><button className="backdrop" onClick={()=>setProfile(false)} aria-label="Close"/><section className="sheet"><i/><button className="close" onClick={()=>setProfile(false)}>×</button><p className="eyebrow">PERSONALISE YOUR START</p><h2>Make the plan yours.</h2><p className="note">Answer only what you want. Bodywise uses this to start gently, avoid obvious mismatches, and make today feel personal before asking you to sign up.</p><fieldset><legend>Training target</legend><div className="choices target-choices">{(Object.keys(goals) as Goal[]).map(x=><button className={goal===x?"chosen":""} onClick={()=>chooseGoal(x)} key={x}>{x}</button>)}</div></fieldset><fieldset><legend>Age range</legend><div className="choices ages">{ages.map(x=><button className={age===x?"chosen":""} onClick={()=>setAge(x)} key={x}>{x}</button>)}</div></fieldset><fieldset><legend>Sex · optional health context</legend><div className="choices">{(["Female","Male","Prefer not to say"] as Sex[]).map(x=><button className={sex===x?"chosen":""} onClick={()=>setSex(x)} key={x}>{x}</button>)}</div></fieldset><fieldset><legend>Experience</legend><div className="choices">{(["Beginner","Intermediate","Advanced"] as Level[]).map(x=><button className={level===x?"chosen":""} onClick={()=>setLevel(x)} key={x}>{x}</button>)}</div></fieldset><fieldset><legend>Pain / limitations</legend><div className="choices limitation-choices">{(["None","Knee sensitive","Back sensitive","Wrist/shoulder sensitive"] as Limitation[]).map(x=><button className={limitation===x?"chosen":""} onClick={()=>setLimitation(x)} key={x}>{x}</button>)}</div><p className="micro-note">Bodywise is not medical care. This simply nudges the plan toward gentler swaps and clearer caution.</p></fieldset><div className="preview"><span>{goal} practice</span><b>{minutes} min · {plan.length} targeted movements · {limitation==="None"?"standard pacing":limitation} · {vault.length} vault variations</b></div><button className="save" onClick={saveProfile}>Save my plan</button></section></div>}
  {session&&<section className="session premium-session" role="dialog" aria-modal="true"><header><button onClick={()=>{setSession(false);setRunning(false)}}>×</button><span>{goal.toUpperCase()} · MOVE {active+1} OF {plan.length}</span><button>◒</button></header><div className="live-metrics"><span><small>HEART RATE · DEMO</small><b>124 <i>BPM</i></b></span><span><small>EFFORT · DEMO</small><b>6 <i>/10</i></b></span><span><small>ACTIVE · DEMO</small><b>38 <i>KCAL</i></b></span></div><div className="session-title"><p>{current.family}</p><h2>{current.name}</h2></div><div className="session-visual"><MovementMedia move={current} large/></div><div className="session-tools"><button className={audioHints?"on":""} onClick={()=>setAudioHints(v=>!v)}>◖ Audio hints</button><button className={caption?"on":""} onClick={()=>setCaption(v=>!v)}>CC Captions</button><button onClick={()=>setRotation(v=>(v+1)%3)}>◐ Swap</button><button>♫ Focus mix</button></div>{caption&&<p className="caption">{current.detail}</p>}<div className="cue"><span>COACH KAI</span><b>{current.cue}</b><p>{audioHints?"Audio hint on · ":""}{current.detail}</p></div><div className="timer-row"><div className="timer" style={{background:"conic-gradient(#e8ff48 "+((current.seconds-left)/current.seconds*100)+"%,#2e302a 0)"}}><div><b>{left}</b><span>SECONDS</span></div></div><button onClick={()=>setRunning(v=>!v)}>{running?"Ⅱ":"▶"}<span>{running?"Pause":"Resume"}</span></button><button className="next" onClick={next}>→<span>{active===plan.length-1?"Finish":"Next"}</span></button></div><div className="session-progress"><i style={{width:((active+1)/plan.length*100)+"%"}}/></div></section>}
  {showUpgrade&&<div className="overlay finish" role="dialog" aria-modal="true"><button className="backdrop" onClick={()=>setShowUpgrade(false)} aria-label="Close"/><section className="finish-card upgrade-card"><span>✦</span><p className="eyebrow">BODYWISE PREMIUM</p><h2>Unlock your personal 4-week strength path.</h2><p>Workout guidance that adapts to your body, not just your motivation. Start with a 7-day free trial after you have seen your first tailored session.</p><div className="premium-list"><b>Premium includes</b>{["Smarter weekly progression","Knee-safe and beginner-safe alternatives","Full real-person movement video library","Saved progress and Body Confidence path","No repeated generic routines","Replace-this-move alternatives"].map(x=><small key={x}>✓ {x}</small>)}</div><div className="pricing-grid"><button><small>Monthly</small><b>$8.99</b><span>Flexible start</span></button><button className="best"><small>Best value</small><b>$59.99</b><span>Yearly · save 44%</span></button><button><small>Launch</small><b>$89.99</b><span>Lifetime early offer</span></button></div><div className="price-row"><b>$0</b><span>7-day free trial first. Cancel anytime before billing.</span></div><button className="share-result" onClick={()=>setShowUpgrade(false)}>Start 7-day free trial</button><button className="done" onClick={()=>setShowUpgrade(false)}>Keep free starter plan</button></section></div>}
  {finish&&<div className="overlay finish" role="dialog" aria-modal="true"><button className="backdrop" onClick={()=>setFinish(false)} aria-label="Close"/><section className="finish-card"><span>✓</span><p className="eyebrow">SESSION COMPLETE</p><h2>{identity} unlocked.</h2><p>You completed your first Bodywise assessment. Keep using free starter workouts, or turn this into a 4-week path with smarter progression and body-aware alternatives.</p><div className="summary-metrics"><b>{minutes}<small>MIN</small></b><b>{plan.length}<small>MOVES</small></b><b>+1<small>STREAK</small></b></div><div className="rating"><small>HOW DID THAT FEEL?</small><div>{["Too easy","Just right","Too hard"].map(x=><button key={x}>{x}</button>)}</div></div><button className="share-result" onClick={()=>{setFinish(false);setShowUpgrade(true)}}>Unlock my 4-week path</button><button className="done" onClick={()=>{setFinish(false);setRotation(v=>(v+1)%3)}}>Keep free daily workout</button></section></div>}
 </main>}
function PlanPage({goal,minutes}:{goal:Goal;minutes:number}){const days=[{d:"MON",n:"14",s:"DONE",t:"Foundation"},{d:"TUE",n:"15",s:"REST",t:"Mobility"},{d:"WED",n:"16",s:"TODAY",t:goal},{d:"FRI",n:"18",s:"UP NEXT",t:"Fresh rotation"},{d:"SUN",n:"20",s:"OPTIONAL",t:"Skill prep"}];return <section className="platform-page plan-page"><p className="eyebrow">YOUR CUSTOM PLAN</p><h1>Stay<br/><em>curious.</em></h1><p className="page-lede">A flexible week that rotates movement families so users get novelty without losing structure.</p><div className="plan-summary"><span><b>3</b> days / week</span><span><b>{minutes}</b> min / session</span><span><b>{Object.keys(goals).length}</b> goal packs</span></div><div className="week-plan">{days.map(x=><article className={x.s==="TODAY"?"today":""} key={x.d}><div><small>{x.d}</small><b>{x.n}</b></div><span>{x.s}</span><h3>{x.t}</h3><p>{x.s==="REST"?"Breathe · stretch · walk":minutes+" min · Coach Kai"}</p>{x.s==="TODAY"&&<button>Start →</button>}</article>)}</div><div className="plan-controls"><h2>Plan upgrades</h2><button><span>Rotation logic</span><b>3 versions per goal →</b></button><button><span>Boredom guard</span><b>Shuffle + vault →</b></button><button><span>Media promise</span><b>Synced across app →</b></button></div><div className="coach-program"><span>COACH KAI · BLOCK 1</span><h2>Own the basics, then vary them.</h2><p>The app now teaches families, progressions and swaps — the part that keeps people from quitting after week one.</p><i>WEEK 2 OF 4</i></div></section>}
function CommunityPage({kudos,onKudos}:{kudos:number;onKudos:()=>void}){return <section className="platform-page community-page"><p className="eyebrow">BODYWISE CLUB</p><h1>Better<br/><em>together.</em></h1><p className="page-lede">A supportive, opt-in space for showing up — with weekly variety challenges.</p><article className="challenge"><span>THIS WEEK’S CHALLENGE</span><h2>Try 3 different rotations.</h2><div><i style={{width:"58%"}}/></div><p><b>7</b> of 12 sessions · 13 days left</p><button>View challenge →</button></article><div className="club-strip"><span><b>2,418</b> members</span><span><b>386</b> trained today</span><span><b>94%</b> supportive</span></div><div className="feed"><h2>Club feed</h2><article><div className="member">AR</div><div><b>Amara R.</b><small>2 HOURS AGO · CORE CONTROL</small><p>The side plank rotation finally made core day feel different.</p><button onClick={onKudos}>▲ {kudos} kudos</button><button>Reply</button></div></article><article><div className="member rust">JL</div><div><b>Jon L.</b><small>YESTERDAY · QUIET SWEAT</small><p>Quiet conditioning in a hotel room. Zero jumping, still sweaty.</p><button>▲ 24 kudos</button><button>Reply</button></div></article></div><p className="privacy-note">Community sharing is opt-in. Your age, sex and health context stay private.</p></section>}
function ProgressPage({goal}:{goal:Goal}){return <section className="platform-page progress-page"><p className="eyebrow">YOUR PROGRESS</p><h1>Proof of<br/><em>practice.</em></h1><p className="page-lede">Track consistency, capacity, movement variety and the skills you are earning.</p><div className="score-grid"><article><span>THIS WEEK</span><b>3<small>/3</small></b><p>sessions complete</p></article><article><span>VARIETY SCORE</span><b>84<small>%</small></b><p>new movement exposure</p></article><article><span>TRAINING TIME</span><b>62<small> MIN</small></b><p>+14% vs last week</p></article><article><span>FOCUS</span><b className="focus-score">{goal}</b><p>current block</p></article></div><article className="load-chart"><div><span>TRAINING LOAD</span><b>Balanced</b></div><div className="bars">{[42,61,36,78,58,90,70].map((x,i)=><i key={i} style={{height:x+"%"}}/>)}</div>{["MON","TUE","WED","THU","FRI","SAT","SUN"].map(x=><small key={x}>{x}</small>)}</article><article className="skill-path"><span>SKILL PATH · PUSH-UP</span><h2>Build it one step at a time.</h2>{["Wall push-up","Incline push-up","Slow negative","Full push-up"].map((x,i)=><div className={i<2?"done":i===2?"current":""} key={x}><i>{i<2?"✓":i+1}</i><span><b>{x}</b><small>{i<2?"Mastered":i===2?"In progress · 68%":"Locked"}</small></span></div>)}</article><article className="latest-win"><span>YOUR LATEST WIN</span><h2>Unlocked rotation variety</h2><p>More choices, same bodyweight foundation, Bodywise-owned media preferred.</p><button>Share achievement →</button></article></section>}














